// ===== 36-models: модели владельца из «3d assets» =====
// Сгенерировано tools/glb2module.py — РУКАМИ НЕ ПРАВИТЬ.
// Геометрия + UV + ИСХОДНЫЕ НОРМАЛИ; цвет даёт палитровый атлас пачки.
// Индексный буфер сохранён из файла: он кодирует, где шов жёсткий, а где
// гладкий, поэтому модель шейдится ровно так, как задумал её автор.
// Реестр палитровых атласов: у КАЖДОЙ пачки моделей (звери, еда, машины)
// СВОЙ colormap. Пока пачка была одна, атлас тоже был один — со второй все
// модели брали бы чужую палитру.
// (пост-генерация, зона ФИЗИКИ): повторная декларация MODEL_ATLASES удалена —
// реестр объявлен в 36-models, этот модуль только ДОПОЛНЯЕТ его ключом 'rock'.
// (пост-генерация): дубль кэша _atlasTex удалён — кэш общий, объявлен в 36-models.
function modelColormap(pack){
  if (_atlasTex[pack]) return _atlasTex[pack];
  // ⚠️ 1×1 БЕЛАЯ ЗАГЛУШКА до декода PNG. Без неё у текстуры первые кадры нет
  // изображения вовсе, выборка даёт нули, а шейдер МНОЖИТ на неё — модели
  // вспыхивают ЧЁРНЫМ на старте уровня. Белая заглушка нейтральна: множитель
  // 1.0, предмет просто секунду виден без раскраски. Небу такую же заглушку
  // подложили в 10-stage — причина та же.
  const stub = document.createElement('canvas');
  stub.width = stub.height = 1;
  const sg = stub.getContext('2d');
  sg.fillStyle = '#fff'; sg.fillRect(0, 0, 1, 1);
  const img = new Image();
  const t = new THREE.Texture(stub);
  t.flipY = false;                 // glTF считает UV от ВЕРХНЕГО левого угла
  t.encoding = THREE.sRGBEncoding;
  t.magFilter = t.minFilter = THREE.LinearFilter;
  t.generateMipmaps = false;       // полосы атласа узкие, мипы смешали бы их
  // подменяем источник только КОГДА картинка готова — обе картинки
  // image-подобные, путь загрузки в three один и тот же
  img.onload = () => { t.image = img; t.needsUpdate = true; };
  img.src = MODEL_ATLASES[pack];
  _atlasTex[pack] = t;
  return t;
}
function modelGeo(pos, nrm, uv, idx){
  const g = new THREE.BufferGeometry();
  g.setAttribute('position', new THREE.BufferAttribute(pos, 3));
  g.setIndex(new THREE.BufferAttribute(idx, 1));
  if (uv) g.setAttribute('uv', new THREE.BufferAttribute(uv, 2));
  // нормали ИЗ ФАЙЛА: сглаживание там, где его задумал автор модели
  if (nrm) g.setAttribute('normal', new THREE.BufferAttribute(nrm, 3));
  else g.computeVertexNormals();
  return g;
}
